// Format a Ramsisa schedule webhook payload as a Slack message.
// Payload shape (per https://schedule.ramsisa.com/docs/api-reference/):
//   { schedule_id, status, download_url, summary: { total_visits, total_days } }
// `download_url` is a relative path (e.g. "/api/v1/schedules/{id}/download/")
// unless the Schedule server has SCHEDULE_PUBLIC_BASE_URL set, in which case
// it is absolute. Only emit a clickable link in the absolute case.

const j = $json;
const status = (j.status || 'unknown').toString();
const icon = status === 'completed' ? ':white_check_mark:' : status === 'failed' ? ':x:' : ':hourglass:';

const lines = [
  `${icon} *Ramsisa schedule ${status}*`,
  `*Schedule ID:* \`${j.schedule_id ?? '—'}\``,
];

if (j.summary && typeof j.summary === 'object') {
  const s = j.summary;
  const summaryBits = [
    s.total_visits != null ? `${s.total_visits} visits` : null,
    s.total_days != null ? `${s.total_days} days` : null,
  ].filter(Boolean);
  if (summaryBits.length) lines.push(`*Summary:* ${summaryBits.join(' · ')}`);
}

if (status === 'completed' && typeof j.download_url === 'string' && j.download_url) {
  if (/^https?:\/\//i.test(j.download_url)) {
    lines.push(`<${j.download_url}|Download CSV>`);
  } else {
    lines.push(`_Download path: \`${j.download_url}\` — fetch via the Ramsisa API. Set SCHEDULE_PUBLIC_BASE_URL on the Ramsisa server to get an absolute URL._`);
  }
}
if (status === 'failed' && j.error) {
  lines.push(`*Error:* ${j.error}`);
}

return { json: { text: lines.join('\n'), status } };
